import pytest
from source import get_user_display_name

def test_get_user_display_name_null_handling_profile():
    user_data = {'profile': None}
    with pytest.raises(TypeError):
        get_user_display_name(user_data)

def test_get_user_display_name_none_profile(capsys):
    user_data = {'profile': None}
    with pytest.raises(TypeError):
        get_user_display_name(user_data)
    captured = capsys.readouterr()
    assert 'NoneType' in captured.out and 'TypeError' in captured.out
